import type { DeviceOS } from '../../types';

import { parseCookieValue } from '@nordic/utils/cookie';
import { getReq } from '@meli/server-context';

import { DC_COOKIE, DC_COOKIE_DICTIONARY } from './constants';

function getDeviceInfoFromCookie(cookieValue: string | undefined) {
  if (!cookieValue) {
    return null;
  }

  return parseCookieValue(cookieValue, DC_COOKIE_DICTIONARY);
}

export function getDeviceOSFromWebview(): DeviceOS | undefined {
  const { cookies, device } = getReq();
  const { source, osName, osVersion } =
    getDeviceInfoFromCookie(cookies[DC_COOKIE]) || {};

  if (source === 'wk') {
    return osName ? { name: osName, version: osVersion } : undefined;
  }

  const name = device.nativeApp?.os || device.webviewOSInfo?.name || osName;
  const version =
    device.webviewOSInfo?.version || device.osVersion || osVersion;

  return name ? { name, version } : undefined;
}
